const outputString = $input.item.json.output;
let cleaned = outputString.trim();

// Remove markdown code fences se existirem
cleaned = cleaned.replace(/^```json\s*/i, '').replace(/\s*```$/i, '');

// Remove marcador <<FIM>> se existir
cleaned = cleaned.replace(/<<FIM>>/g, '');

// Encontra o primeiro JSON completo contando chaves { }
let depth = 0, start = -1, end = -1;
for (let i = 0; i < cleaned.length; i++) {
  if (cleaned[i] === '{') {
    if (depth === 0) start = i;
    depth++;
  } else if (cleaned[i] === '}') {
    depth--;
    if (depth === 0) { end = i + 1; break; }
  }
}

const jsonString = cleaned.substring(start, end);
const data = JSON.parse(jsonString);

return [{
  json: {
    message: data.message,
    etapa: data.etapa,
    tipo_servico: data.tipo_servico || null,
    dados_coletados: data.dados_coletados,
    pronto_para_cotacao: data.pronto_para_cotacao,
    cotacao_multipla: data.cotacao_multipla || false,
    dados_multiplos: data.dados_multiplos || null,
    handoff: data.handoff,
    confidence: data.confidence,
    reason: data.reason,
    notify_text: data.notify_text || null
  }
}];

// 1. Dados do Webhook
const webhookData = $input.first().json;
const body = webhookData.body;
const query = webhookData.query;

// 2. Mapeamento hotel_resort
const mapeamento = {
  'central_gravatal': { name_hotel_resort: 'Central Termas de Gravatal', is_central: true },
  'hotel_internacional': { name_hotel_resort: 'Hotel Internacional Gravatal', is_central: false },
  'termas_gravatal': { name_hotel_resort: 'Hotel Termas (Gravatal)', is_central: false },
  'termas_do_lago': { name_hotel_resort: 'Hotel Termas do Lago', is_central: false },
  'cabanas': { name_hotel_resort: 'Cabanas Termas Hotel', is_central: false },
  'park_hotel': { name_hotel_resort: 'Termas Park Hotel', is_central: false },
  'fazzenda': { name_hotel_resort: 'Fazzenda Park Resort', is_central: false },
  'ita_thermas': { name_hotel_resort: 'Itá Thermas Resort e Spa', is_central: false },
  'machadinho_thermas': { name_hotel_resort: 'Machadinho Thermas Resort SPA', is_central: false },
  'central_jurema': { name_hotel_resort: 'Central Jurema Águas Quentes', is_central: true },
  'lagos_de_jurema': { name_hotel_resort: 'Lagos de Jurema', is_central: false },
  'jardins_de_jurema': { name_hotel_resort: 'Jardins de Jurema', is_central: false },
  'central_piratuba': { name_hotel_resort: 'Central Piratuba', is_central: true },
  'tirolesa': { name_hotel_resort: 'Hotel Tirolesa', is_central: false },
  'aguas_de_palmas': { name_hotel_resort: 'Águas de Palmas', is_central: false },
  'dona_francisca': { name_hotel_resort: 'Dona Francisca', is_central: false },
  'recanto_cataratas_resort': { name_hotel_resort: 'Recanto Cataratas Resort', is_central: false },
  'central_resorts': { name_hotel_resort: 'Central Resorts', is_central: true },
  'mabu_thermas': { name_hotel_resort: 'Mabu Thermas Grand Resort', is_central: false },
  'vivaz_cataratas': { name_hotel_resort: 'Vivaz Cataratas Resort', is_central: false },
  'central_gramado': { name_hotel_resort: 'Central Gramado', is_central: true }
};

// 3. Resolve hotel_resort
const hotelResortKey = query.assistant || body['data[hotel]'] || '';
const infoHotel = mapeamento[hotelResortKey] || {};
const isBuffer = query.buffer === 'true';

return [{
  json: {
    // === DADOS DO HOTEL ===
    hotel_resort: hotelResortKey,
    name_hotel_resort: infoHotel.name_hotel_resort || '',
    is_central: infoHotel.is_central ?? false,
    is_buffer: isBuffer,

    // === QUERY ===
    query: query,

    // === DADOS DO WEBHOOK ===
    message: body['data[message]'] || '',
    lead_id: body['data[lead_id]'] || '',
    contact_id: body['data[contact_id]'] || '',
    name: body['data[name]'] || '',
    phone: body['data[phone]'] || '',
    return_url: body['return_url'] || '',
    token: body['token'] || '',

    // === METADATA ===
    origem: 'webhook_direto'
  }
}];

// Pega os dados coletados
const dadosColetados = $item(0).$node["Motiva Pausa"].json.dados_coletados;

// Função para converter e validar data
function converterData(dataStr) {
  let dia, mes, ano;

  // Verifica se tem ano (formato DD/MM/YYYY ou DD/MM)
  const partes = dataStr.split('/');

  if (partes.length === 2) {
    // Formato DD/MM - adiciona ano atual
    [dia, mes] = partes;
    ano = new Date().getFullYear().toString();
  } else if (partes.length === 3) {
    // Formato DD/MM/YYYY
    [dia, mes, ano] = partes;
  } else {
    throw new Error(`Formato de data inválido: ${dataStr}`);
  }

  return `${ano}-${mes.padStart(2, '0')}-${dia.padStart(2, '0')}`;
}

// Separa as crianças por faixa etária
let criancas_0_4 = 0;
let criancas_5_12 = 0;

if (dadosColetados.idades_criancas && dadosColetados.idades_criancas.length > 0) {
  dadosColetados.idades_criancas.forEach(idade => {
    if (idade >= 0 && idade <= 4) {
      criancas_0_4++;
    } else if (idade >= 5 && idade <= 12) {
      criancas_5_12++;
    }
  });
}

// Monta os parâmetros
const checkin = converterData(dadosColetados.data_entrada);
const checkout = converterData(dadosColetados.data_saida);
const adultos = dadosColetados.adultos;

// Monta a URL completa
const baseUrl = "http://20.206.241.99:8000/api/v1/precos/internacionalgravatal";
const url = `${baseUrl}?checkin=${checkin}&checkout=${checkout}&adultos=${adultos}&criancas_0_4=${criancas_0_4}&criancas_5_12=${criancas_5_12}`;

// Retorna os dados estruturados
return {
  checkin: checkin,
  checkout: checkout,
  adultos: adultos,
  criancas_0_4: criancas_0_4,
  criancas_5_12: criancas_5_12,
  url: url,
  email: dadosColetados.email,
  total_criancas: dadosColetados.criancas
};

const dados = $item(0).$node["Orcamento"].json;

if (!dados || !dados.opcoes || dados.opcoes.length === 0) {
  return {
    mensagem: "😔 Infelizmente não encontramos disponibilidade para as datas solicitadas. Por favor, tente outras datas ou entre em contato conosco para mais opções!",
    imagem: null
  };
}

// Converte as datas corretamente sem problema de timezone
const [anoIn, mesIn, diaIn] = dados.busca.checkin.split('-');
const [anoOut, mesOut, diaOut] = dados.busca.checkout.split('-');

const dataEntrada = `${diaIn}/${mesIn}/${anoIn}`;
const dataSaida = `${diaOut}/${mesOut}/${anoOut}`;

// Calcula número de diárias usando as strings diretas
const checkin = new Date(dados.busca.checkin + 'T12:00:00');
const checkout = new Date(dados.busca.checkout + 'T12:00:00');
const umDia = 24 * 60 * 60 * 1000;
const diarias = Math.round(Math.abs((checkout - checkin) / umDia));

const adultos = dados.busca.hospedes.adultos;
const criancas = dados.busca.hospedes.criancas_0_4 + dados.busca.hospedes.criancas_5_12;

let textoHospedes = `👥 ${adultos} adulto${adultos > 1 ? 's' : ''}`;
if (criancas > 0) {
  textoHospedes += ` + ${criancas} criança${criancas > 1 ? 's' : ''}`;
}

let mensagem = `*Orçamento:*\n`;
mensagem += `🏨 *${dados.hotel.nome}*\n`;
mensagem += `📍 ${dados.hotel.localizacao}\n`;
mensagem += `📅 Check-in: ${dataEntrada}\n`;
mensagem += `📅 Check-out: ${dataSaida}\n`;
mensagem += `${textoHospedes}\n\n`;

mensagem += `🍽 *Incluso na diária – Pensão Completa (05 refeições):*\n`;
mensagem += `☕ Café da manhã – 07h30 às 10h00\n`;
mensagem += `🍢 Petiscos na piscina – 11h00 às 12h00\n`;
mensagem += `🍽 Almoço – 12h00 às 14h00\n`;
mensagem += `🍵 Chá da tarde – 16h00 às 17h00\n`;
mensagem += `🍝 Jantar – 19h30 às 21h30\n\n`;

mensagem += `🥤 *Bebidas incluídas:*\n`;
mensagem += `🍺 Chopp liberado no bar piscina das 11h às 13h (Marca Regional Berg Brau)\n`;
mensagem += `🥤 Água sem gás, suco e refrigerante servidos em taças ou copos durante almoço e jantar\n`;
mensagem += `*Demais bebidas pagas à parte*\n\n`;

mensagem += `💵 *Valores da hospedagem:*\n\n`;

const primeiraOpcao = dados.opcoes[0];
mensagem += `${dataEntrada} - ${dataSaida}\n`;
mensagem += `*${primeiraOpcao.apartamento}*\n`;
mensagem += `Adulto(s): ${adultos}\n`;
if (criancas > 0) {
  mensagem += `Crianças: ${criancas}\n`;
}
mensagem += `Pensão: ${primeiraOpcao.pensao}\n`;
mensagem += `Tarifa: ${primeiraOpcao.tarifa}\n`;
mensagem += `${diarias} diária${diarias > 1 ? 's' : ''}\n`;
mensagem += `*${primeiraOpcao.preco_total}*\n\n`;

const totalParaMostrar = Math.min(3, dados.opcoes.length);
for (let i = 1; i < totalParaMostrar; i++) {
  mensagem += `*${dados.opcoes[i].apartamento.toUpperCase()}* - consultar\n`;
}

mensagem += `\n*Formas de pagamento* 👇\n`;
mensagem += `💳 Sinal de 25% + saldo em até 10x no cartão via link (no ato da reserva)\n`;
mensagem += `💳 Parcelamento total sem entrada em até 10x (parcela mínima R$ 200,00)\n\n`;

mensagem += `🕒 Check-in: 15h\n`;
mensagem += `🕛 Check-out: 12h (almoço incluso)\n\n`;

mensagem += `⚠ *Observação:* Tarifas flutuantes, se não reservado não há garantia de valores.`;

const imagemPrincipal = dados.opcoes[0].imagens[0];

return {
  mensagem: mensagem,
  imagem: imagemPrincipal,
  hotel: dados.hotel.nome,
  checkin: dataEntrada,
  checkout: dataSaida,
  diarias: diarias,
  total_opcoes: dados.resumo.total_opcoes,
  valor_minimo: dados.resumo.mais_barato,
  valor_maximo: dados.resumo.mais_caro,
  opcoes_completas: dados.opcoes
};

// Pega os dados coletados
const dadosColetados = $item(0).$node["Code"].json.dados_coletados;
const hotelCode = $item(0).$node["Webhook"].json.query.assistant;

// Função para converter e validar data
function converterData(dataStr) {
  const partes = dataStr.split('/');
  let dia, mes, ano;

  if (partes.length === 2) {
    [dia, mes] = partes;
    ano = new Date().getFullYear().toString();
  } else if (partes.length === 3) {
    [dia, mes, ano] = partes;
  } else {
    throw new Error(`Formato de data inválido: ${dataStr}`);
  }

  return `${ano}-${mes.padStart(2, '0')}-${dia.padStart(2, '0')}`;
}

// Ordena idades do mais novo ao mais velho
// (a API já aplica a regra: max 1 cortesia por AP, restante pagante por faixa etária)
const idades = [...(dadosColetados.idades_criancas || [])]
  .map(idade => Math.floor(Number(idade)))
  .filter(idade => idade >= 3)
  .sort((a, b) => a - b);

// Formato esperado pela API: "3,11" ou "" se sem crianças
const criancas_idades = idades.length > 0 ? idades.join(',') : '';

const checkin  = converterData(dadosColetados.data_entrada);
const checkout = converterData(dadosColetados.data_saida);

return {
  hotel_code:         hotelCode,
  checkin:            checkin,
  checkout:           checkout,
  adultos:            dadosColetados.adultos,
  criancas_idades:    criancas_idades,
  email:              dadosColetados.email,
  apartamento_num:    1,
  total_apartamentos: 1,
  total_datas:        1
};

const dados = $item(0).$node["Orcamento3"].json;
const { hotel: hotelResort, config } = $item(0).$node["Config Hoteis"].json;

function parsePreco(str) {
  if (!str) return Infinity;
  return Number(str.replace(/[R$\s.]/g, '').replace(',', '.'));
}
if (dados && dados.opcoes) {
  dados.opcoes.sort((a, b) => parsePreco(a.preco_total) - parsePreco(b.preco_total));
}

if (!dados || !dados.opcoes || dados.opcoes.length === 0) {
  return {
    mensagem:
      "☹ Infelizmente não encontramos disponibilidade para as datas solicitadas. Gostaria de verificar outras datas disponíveis?",
    imagem: null,
  };
}

const [anoIn, mesIn, diaIn] = dados.busca.checkin.split("-");
const [anoOut, mesOut, diaOut] = dados.busca.checkout.split("-");
const dataEntrada = `${diaIn}/${mesIn}/${anoIn}`;
const dataSaida = `${diaOut}/${mesOut}/${anoOut}`;

const checkin = new Date(dados.busca.checkin + "T12:00:00");
const checkout = new Date(dados.busca.checkout + "T12:00:00");
const diarias = Math.round(
  Math.abs((checkout - checkin) / (24 * 60 * 60 * 1000)),
);

const adultos = dados.busca.hospedes.adultos;
const criancasIdades = dados.busca.hospedes.criancas_idades;
const criancas = criancasIdades
  ? criancasIdades.split(",").filter((x) => x.trim() !== "").length
  : 0;

const primeiraOpcao = dados.opcoes[0];
const totalParaMostrar = Math.min(3, dados.opcoes.length);

let mensagem = "";

// ============================================================
// TERMAS PARK HOTEL
// ============================================================
if (hotelResort === "park_hotel") {
  const totalPessoas = adultos + criancas;
  let totalPessoasTexto = `${adultos} adulto${adultos > 1 ? "s" : ""}`;
  if (criancas > 0)
    totalPessoasTexto += ` + ${criancas} criança${criancas > 1 ? "s" : ""}`;

  mensagem += config.titulo + `\n\n`;
  mensagem += `☉ *Período:* ${dataEntrada} a ${dataSaida} (${diarias} diária${diarias > 1 ? "s" : ""})\n\n`;
  mensagem += `☺ *Hospedagem para:* ${totalPessoasTexto} (${totalPessoas} pessoa${totalPessoas > 1 ? "s" : ""})\n\n`;

  mensagem += `✦ *Valor total do pacote:*\n\n`;
  mensagem += `▶ *${primeiraOpcao.preco_total}*\n`;
  for (let i = 1; i < totalParaMostrar; i++) {
    mensagem += `*${dados.opcoes[i].apartamento.toUpperCase()}* - consultar\n`;
  }
  mensagem += "\n";

  mensagem += config.pensao + `\n\n`;
  mensagem += config.estrutura + `\n\n`;
  mensagem += config.recreacao + `\n\n`;
  mensagem += config.servicos + `\n\n`;
  mensagem += config.pagamento + `\n\n`;
  mensagem += config.checkin + `\n`;
  mensagem += config.checkout + `\n\n`;
  mensagem += config.obs;
  if (config.aviso) mensagem += `\n\n` + config.aviso;

  // ============================================================
  // HOTEL TERMAS GRAVATAL
  // ============================================================
} else if (hotelResort === "termas_gravatal") {
  mensagem += `*Orçamento:*\n`;
  mensagem += config.subtitulo + `\n\n`;

  mensagem += config.pensao + `\n\n`;
  mensagem += config.estrutura + `\n\n`;

  mensagem += `✦ *Valores Da Hospedagem:*\n\n`;
  mensagem += `${dataEntrada} - ${dataSaida}\n`;
  mensagem += `*${primeiraOpcao.apartamento}*\n`;

  let totalPessoasTexto = `${adultos} adulto${adultos > 1 ? "s" : ""}`;
  if (criancas > 0)
    totalPessoasTexto += ` + ${criancas} criança${criancas > 1 ? "s" : ""}`;
  mensagem += `☺ ${totalPessoasTexto}\n`;
  mensagem += `${diarias} diária${diarias > 1 ? "s" : ""}\n`;
  mensagem += `▶ *${primeiraOpcao.preco_total}*\n\n`;

  for (let i = 1; i < totalParaMostrar; i++) {
    mensagem += `*${dados.opcoes[i].apartamento.toUpperCase()}* - consultar\n`;
  }
  mensagem += "\n";

  mensagem += config.roupao + `\n\n`;
  mensagem += config.horarios_refeicoes + `\n\n`;
  mensagem += config.horarios_piscinas + `\n\n`;
  mensagem += config.horarios_banheiras + `\n\n`;
  mensagem += config.checkin + `\n`;
  mensagem += config.checkout + `\n\n`;
  mensagem += config.obs;
  if (config.aviso) mensagem += `\n\n` + config.aviso;

  // ============================================================
  // HOTEL TERMAS DO LAGO
  // ============================================================
  // ============================================================
  // FAZZENDA PARK RESORT
  // ============================================================
} else if (hotelResort === "fazzenda") {
  const totalPessoas = adultos + criancas;
  let totalPessoasTexto = `${adultos} adulto${adultos > 1 ? "s" : ""}`;
  if (criancas > 0)
    totalPessoasTexto += ` + ${criancas} criança${criancas > 1 ? "s" : ""}`;

  // --- ORÇAMENTO ---
  mensagem += config.titulo + `\n\n`;
  mensagem += `☉ *Período:* ${dataEntrada} a ${dataSaida} (${diarias} diária${diarias > 1 ? "s" : ""})\n`;
  mensagem += `☺ *Hospedagem para:* ${totalPessoasTexto} (${totalPessoas} pessoa${totalPessoas > 1 ? "s" : ""})\n\n`;
  mensagem += `*${primeiraOpcao.apartamento}*\n`;
  mensagem += `▶ *${primeiraOpcao.preco_total}*\n`;
  for (let i = 1; i < totalParaMostrar; i++) {
    mensagem += `*${dados.opcoes[i].apartamento.toUpperCase()}* - consultar\n`;
  }
  mensagem += "\n";
  mensagem += config.pagamento + `\n\n`;
  mensagem += config.checkin + `\n`;
  mensagem += config.checkout + `\n\n`;

  // --- ATIVIDADES ---
  mensagem += config.atividades + `\n\n`;
  mensagem += config.servicos + `\n\n`;

  // --- ALL INCLUSIVE ---
  mensagem += config.allinclusive + `\n\n`;
  mensagem += config.bebidas + `\n\n`;

  mensagem += config.obs;
  if (config.aviso) mensagem += `\n\n` + config.aviso;

  // ============================================================
  // HOTEL TERMAS DO LAGO
  // ============================================================
} else if (hotelResort === "termas_do_lago") {
  mensagem += config.titulo + `\n\n`;
  mensagem += `Data: ${dataEntrada} a ${dataSaida}\n\n`;
  mensagem += `Valor total do pacote para o período solicitado para todos\n\n`;
  mensagem += `▶ *${primeiraOpcao.preco_total}*\n\n`;
  mensagem += config.pensao + `\n\n`;

  for (let i = 1; i < totalParaMostrar; i++) {
    mensagem += `*${dados.opcoes[i].apartamento.toUpperCase()}* - consultar\n`;
  }
  if (totalParaMostrar > 1) mensagem += "\n";

  mensagem += config.pagamento + `\n\n`;
  mensagem += config.checkin_checkout + `\n\n`;
  mensagem += config.amenidades + `\n\n`;
  mensagem += config.estrutura + `\n\n`;
  mensagem += config.obs;
  if (config.aviso) mensagem += `\n\n` + config.aviso;

  // ============================================================
  // MACHADINHO THERMAS RESORT SPA
  // ============================================================
} else if (hotelResort === "machadinho_thermas") {
  const totalPessoas = adultos + criancas;
  let totalPessoasTexto = `${adultos} adulto${adultos > 1 ? "s" : ""}`;
  if (criancas > 0)
    totalPessoasTexto += ` + ${criancas} criança${criancas > 1 ? "s" : ""}`;

  mensagem += config.titulo + `\n\n`;
  mensagem += `☉ *Período:* ${dataEntrada} a ${dataSaida} (${diarias} diária${diarias > 1 ? "s" : ""})\n`;
  mensagem += `☺ *Hospedagem para:* ${totalPessoasTexto} (${totalPessoas} pessoa${totalPessoas > 1 ? "s" : ""})\n\n`;

  mensagem += `✦ *Valor total do pacote:*\n\n`;
  mensagem += `▶ *${primeiraOpcao.preco_total}*\n`;
  for (let i = 1; i < totalParaMostrar; i++) {
    mensagem += `*${dados.opcoes[i].apartamento.toUpperCase()}* - consultar\n`;
  }
  mensagem += "\n";

  mensagem += config.pensao + `\n\n`;
  mensagem += config.bebidas + `\n\n`;
  mensagem += config.piscinas + `\n\n`;
  mensagem += config.pagamento + `\n\n`;
  mensagem += config.recreacao + `\n\n`;
  mensagem += config.costelao + `\n\n`;
  mensagem += config.ovelha + `\n\n`;
  mensagem += config.lama + `\n\n`;
  mensagem += config.chardonnay + `\n\n`;
  mensagem += config.estrutura + `\n\n`;
  mensagem += config.apartamentos + `\n\n`;
  mensagem += config.obs_bebidas + `\n\n`;
  mensagem += config.opcionais + `\n\n`;
  mensagem += config.spa + `\n\n`;
  mensagem += config.checkin + `\n`;
  mensagem += config.checkout + `\n\n`;
  mensagem += config.horarios_refeicoes;
  if (config.aviso) mensagem += `\n\n` + config.aviso;

  // ============================================================
  // ÁGUAS DE PALMAS RESORT
  // ============================================================
} else if (hotelResort === "aguas_de_palmas") {
  const totalPessoas = adultos + criancas;
  let totalPessoasTexto = `${adultos} adulto${adultos > 1 ? "s" : ""}`;
  if (criancas > 0)
    totalPessoasTexto += ` + ${criancas} criança${criancas > 1 ? "s" : ""}`;

  mensagem += config.titulo + `\n`;
  mensagem += config.subtitulo + `\n\n`;
